import numpy as np


def gram_schmidt(vectors):
    """Convert a set of vectors into an orthonormal basis via Gram-Schmidt."""
    vectors = np.asarray(vectors, dtype=float)
    basis = []
    for v in vectors:
        w = v.copy()
        for u in basis:
            w = w - np.dot(w, u) * u
        norm = np.linalg.norm(w)
        if norm < 1e-10:
            continue
        basis.append(w / norm)
    if len(basis) == 0:
        return np.zeros((0, vectors.shape[1]), dtype=float)
    return np.vstack(basis)
